class BankAccount:
    def __init__(self, balance: int):
        self.__balance = balance

    def getbalance(self):
        return self.__balance

    def withdraw(self, m:int):
        if self.__balance < m:
            print('Insufficient balance.', end='')
        else:
            self.__balance -= m

    def deposit(self, m:int):
        self.__balance += m

balance = int(input())
bankAccount = BankAccount(balance)
n = int(input())
for _ in range(n):
    op, m = input().split()
    m = int(m)
    if op == 'w':
        bankAccount.withdraw(m)
    elif op == 'd':
        bankAccount.deposit(m)
    print('balance:', bankAccount.getbalance())
